mapper.select:
SELECT id, site_id, device_id, hour_start, avg_power_kw, max_power_kw, min_power_kw, energy_kwh, avg_pf, avg_voltage, reading_count FROM fact_hourly_energy
AND site_id = #{siteId}
AND device_id = #{deviceId}
AND hour_start >= #{startDate}::timestamp
AND hour_start < (#{endDate}::date + INTERVAL '1 day')
ORDER BY hour_start DESC LIMIT 500

SELECT id, site_id, device_id, reading_date,
       total_energy_kwh, peak_demand_kw,
       avg_power_kw, max_power_kw, min_power_kw,
       avg_pf, avg_voltage, reading_count
FROM fact_daily_energy


        AND site_id = #{siteId}


        AND device_id = #{deviceId}



            AND reading_date BETWEEN #{startDate} AND #{endDate}


            AND reading_date >= #{startDate}


            AND reading_date <= #{endDate}



ORDER BY reading_date DESC
LIMIT 500

SELECT d.site_id, s.site_name, d.reading_date, SUM(d.total_energy_kwh) AS total_energy_kwh, MAX(d.peak_demand_kw) AS peak_demand_kw, AVG(d.avg_power_kw) AS avg_power_kw, COUNT(DISTINCT d.device_id) AS device_count FROM fact_daily_energy d JOIN dim_sites s ON d.site_id = s.site_id
AND d.site_id = #{siteId}
AND d.reading_date >= #{startDate}
AND d.reading_date <= #{endDate}
GROUP BY d.site_id, s.site_name, d.reading_date ORDER BY d.reading_date DESC, d.site_id LIMIT 200
